#!/bin/bash
# Download all images from Sara's Squarespace site
BASE="C:/Users/junk7/KroolWorld/SarasPortfolio/site/public/images"

download() {
  local url="$1"
  local dir="$2"
  local filename=$(echo "$url" | sed 's/.*\///' | sed 's/+/ /g' | sed 's/%2B/+/g' | sed 's/%28/(/g' | sed 's/%29/)/g' | sed 's/%25/%/g')
  # Clean filename - remove URL encoding, spaces to hyphens
  local clean=$(echo "$filename" | sed 's/ /-/g' | sed 's/[()]//g' | tr '[:upper:]' '[:lower:]')
  if [ ! -f "$dir/$clean" ]; then
    curl -sL -o "$dir/$clean" "$url" 2>/dev/null &
  fi
}

